import React, { useState, useEffect } from "react";
import TripForm from "./components/TripForm";
import StationForm from "./components/StationForm";
import TrainForm from "./components/TrainForm";
import RouteForm from "./components/RouteForm"; // форма для добавления маршрута

function App() {
  const [stations, setStations] = useState([]);
  const [trains, setTrains] = useState([]);
  const [routes, setRoutes] = useState([]);
  const [trips, setTrips] = useState([]);

  // Загрузка данных с сервера
  useEffect(() => {
    fetch("http://localhost:5050/stations")
      .then(res => res.json())
      .then(data => setStations(data))
      .catch(console.error);

    fetch("http://localhost:5050/trains")
      .then(res => res.json())
      .then(data => setTrains(data))
      .catch(console.error);

    fetch("http://localhost:5050/routes")
      .then(res => res.json())
      .then(data => setRoutes(data))
      .catch(console.error);

    fetch("http://localhost:5050/trips")
      .then(res => res.json())
      .then(data => setTrips(data))
      .catch(console.error);
  }, []);

  // Обработчики добавления новых данных
  const handleNewStation = (station) => setStations(prev => [...prev, station]);
  const handleNewTrain = (train) => setTrains(prev => [...prev, train]);
  const handleNewRoute = (route) => setRoutes(prev => [...prev, route]);
  const handleNewTrip = (trip) => setTrips(prev => [...prev, trip]);

  return (
    <div style={{ padding: "20px" }}>
      <h1>Транспортная система</h1>

      {/* Станции */}
      <div style={{ marginBottom: "30px" }}>
        <StationForm onNewStation={handleNewStation} />
        <h2>Список станций</h2>
        <ul>
          {stations.map(s => <li key={s.id}>{s.name}</li>)}
        </ul>
      </div>

      {/* Поезда */}
      <div style={{ marginBottom: "30px" }}>
        <TrainForm onNewTrain={handleNewTrain} />
        <h2>Список поездов</h2>
        <ul>
          {trains.map(t => <li key={t.id}>{t.number}</li>)}
        </ul>
      </div>

      {/* Маршруты */}
      <div style={{ marginBottom: "30px" }}>
        <RouteForm 
          stations={stations} 
          onNewRoute={handleNewRoute} 
        />
        <h2>Маршруты</h2>
        <ul>
          {routes.map(r => (
            <li key={r.id}>
              {r.departure} → {r.arrival} 
              {r.stops && r.stops.length > 0
                ? ` (остановки: ${r.stops.join(", ")})`
                : " (остановок нет)"}
            </li>
          ))}
        </ul>
      </div>

      {/* Рейсы */}
      <div style={{ marginBottom: "30px" }}>
        <TripForm
          routes={routes}
          trains={trains}
          onNewTrip={handleNewTrip}
        />
        <h2>Рейсы</h2>
        <ul>
          {trips.map(t => {
            const route = routes.find(r => r.id === t.route_id);
            const train = trains.find(tr => tr.id === t.train_id);
            return (
              <li key={t.id}>
                🚆 Поезд {train ? train.number : t.train_id} — 
                {route ? `${route.departure} → ${route.arrival}` : t.route_id}  
                (Отправление: {t.departure_time}, Прибытие: {t.arrival_time})
              </li>
            );
          })}
        </ul>
      </div>
    </div>
  );
}

export default App;
